import logging
from lxml import etree
from .exceptions import SAMLValidationError

logger = logging.getLogger(__name__)

SAML_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

NAMESPACES = {
    'samlp': SAML_PROTOCOL_NS,
    'saml': SAML_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}


class SAMLXMLValidator:
    """Validates SAML XML structure and extracts data."""

    REQUIRED_RESPONSE_ATTRIBUTES = ['ID', 'Version', 'IssueInstant']
    REQUIRED_ASSERTION_ATTRIBUTES = ['ID', 'Version', 'IssueInstant']
    SAML_VERSION = '2.0'

    def __init__(self, xml_string):
        self.xml_string = xml_string
        self.root = None
        self.errors = []

    def parse(self):
        """Parse the XML string into an element tree."""
        try:
            if isinstance(self.xml_string, str):
                xml_bytes = self.xml_string.encode('utf-8')
            else:
                xml_bytes = self.xml_string

            parser = etree.XMLParser(
                resolve_entities=False,
                no_network=True,
                dtd_validation=False,
                load_dtd=False,
                huge_tree=False,
            )
            self.root = etree.fromstring(xml_bytes, parser=parser)
            return self.root
        except etree.XMLSyntaxError as e:
            raise SAMLValidationError(f"Invalid XML syntax: {e}")

    def validate_structure(self):
        """Validate the overall SAML response structure."""
        if self.root is None:
            self.parse()

        self._validate_root_element()
        self._validate_response_attributes()
        self._validate_status()
        self._validate_assertion_structure()

        if self.errors:
            raise SAMLValidationError(
                f"SAML validation failed: {'; '.join(self.errors)}"
            )
        return True

    def _validate_root_element(self):
        """Validate the root element is a SAML Response."""
        expected_tag = f'{{{SAML_PROTOCOL_NS}}}Response'
        if self.root.tag != expected_tag:
            self.errors.append(
                f"Root element must be samlp:Response, got {self.root.tag}"
            )

    def _validate_response_attributes(self):
        """Validate required attributes on the Response element."""
        for attr in self.REQUIRED_RESPONSE_ATTRIBUTES:
            if self.root.get(attr) is None:
                self.errors.append(
                    f"Response missing required attribute: {attr}"
                )

        version = self.root.get('Version')
        if version and version != self.SAML_VERSION:
            self.errors.append(
                f"Unsupported SAML version: {version}, expected {self.SAML_VERSION}"
            )

    def _validate_status(self):
        """Validate the Status element."""
        status = self.root.find('samlp:Status', NAMESPACES)
        if status is None:
            self.errors.append("Response missing Status element")
            return

        status_code = status.find('samlp:StatusCode', NAMESPACES)
        if status_code is None:
            self.errors.append("Status missing StatusCode element")
            return

        status_value = status_code.get('Value')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            status_message = status.find('samlp:StatusMessage', NAMESPACES)
            msg = status_message.text if status_message is not None else 'Unknown'
            self.errors.append(
                f"SAML authentication failed. Status: {status_value}, Message: {msg}"
            )

    def _validate_assertion_structure(self):
        """Validate the Assertion element structure."""
        assertions = self.root.findall('saml:Assertion', NAMESPACES)

        if len(assertions) == 0:
            self.errors.append("Response contains no Assertion elements")
            return

        for assertion in assertions:
            self._validate_single_assertion(assertion)

    def _validate_single_assertion(self, assertion):
        """Validate a single Assertion element."""
        for attr in self.REQUIRED_ASSERTION_ATTRIBUTES:
            if assertion.get(attr) is None:
                self.errors.append(
                    f"Assertion missing required attribute: {attr}"
                )

        version = assertion.get('Version')
        if version and version != self.SAML_VERSION:
            self.errors.append(
                f"Assertion has unsupported SAML version: {version}"
            )

        issuer = assertion.find('saml:Issuer', NAMESPACES)
        if issuer is None:
            self.errors.append("Assertion missing Issuer element")

        subject = assertion.find('saml:Subject', NAMESPACES)
        if subject is None:
            self.errors.append("Assertion missing Subject element")
        else:
            name_id = subject.find('saml:NameID', NAMESPACES)
            if name_id is None:
                self.errors.append("Subject missing NameID element")

        conditions = assertion.find('saml:Conditions', NAMESPACES)
        if conditions is None:
            logger.warning("Assertion missing Conditions element (recommended)")

        authn_statement = assertion.find('saml:AuthnStatement', NAMESPACES)
        if authn_statement is None:
            logger.warning("Assertion missing AuthnStatement element")

    def get_status_code(self):
        """Extract the status code from the response."""
        if self.root is None:
            self.parse()
        status_code = self.root.find('samlp:Status/samlp:StatusCode', NAMESPACES)
        if status_code is not None:
            return status_code.get('Value')
        return None


