import base64
import zlib
import logging
from datetime import datetime, timezone
from lxml import etree
from .xml_validator import SAMLXMLValidator, NAMESPACES, SAML_ASSERTION_NS
from .exceptions import SAMLResponseError, SAMLValidationError

logger = logging.getLogger(__name__)


class SAMLResponseParser:
    """Parses SAML POST responses and extracts user information."""

    def __init__(self, saml_response_b64, validate=True):
        self.saml_response_b64 = saml_response_b64
        self.xml_string = None
        self.root = None
        self.validator = None
        self.should_validate = validate
        self._decoded = False

    def decode_response(self):
        """Decode the base64-encoded SAML response."""
        try:
            xml_bytes = base64.b64decode(self.saml_response_b64)
        except Exception as e:
            raise SAMLResponseError(f"Failed to base64 decode SAML response: {e}")

        try:
            self.xml_string = xml_bytes.decode('utf-8')
        except UnicodeDecodeError:
            try:
                decompressed = zlib.decompress(xml_bytes, -15)
                self.xml_string = decompressed.decode('utf-8')
            except Exception:
                raise SAMLResponseError("Failed to decode SAML response XML")

        self._decoded = True
        logger.debug("SAML response decoded successfully")
        return self.xml_string

    def parse_and_validate(self):
        """Parse and validate the SAML response."""
        if not self._decoded:
            self.decode_response()

        self.validator = SAMLXMLValidator(self.xml_string)
        self.root = self.validator.parse()

        if self.should_validate:
            self.validator.validate_structure()

        return self.root

    def get_name_id(self):
        """Extract the NameID from the SAML assertion."""
        if self.root is None:
            self.parse_and_validate()

        name_id_elem = self.root.find(
            'saml:Assertion/saml:Subject/saml:NameID', NAMESPACES
        )
        if name_id_elem is None:
            raise SAMLResponseError("No NameID found in SAML response")

        return {
            'value': name_id_elem.text.strip() if name_id_elem.text else '',
            'format': name_id_elem.get('Format', ''),
            'sp_name_qualifier': name_id_elem.get('SPNameQualifier', ''),
            'name_qualifier': name_id_elem.get('NameQualifier', ''),
        }

    def get_issuer(self):
        """Extract the Issuer from the SAML response."""
        if self.root is None:
            self.parse_and_validate()

        issuer = self.root.find('saml:Issuer', NAMESPACES)
        if issuer is not None and issuer.text:
            return issuer.text.strip()

        assertion_issuer = self.root.find(
            'saml:Assertion/saml:Issuer', NAMESPACES
        )
        if assertion_issuer is not None and assertion_issuer.text:
            return assertion_issuer.text.strip()

        return None

    def get_session_index(self):
        """Extract the SessionIndex from the AuthnStatement."""
        if self.root is None:
            self.parse_and_validate()

        authn_statement = self.root.find(
            'saml:Assertion/saml:AuthnStatement', NAMESPACES
        )
        if authn_statement is not None:
            return authn_statement.get('SessionIndex', '')
        return ''

    def get_session_expiry(self):
        """Extract session expiry from AuthnStatement or Conditions."""
        if self.root is None:
            self.parse_and_validate()

        authn_statement = self.root.find(
            'saml:Assertion/saml:AuthnStatement', NAMESPACES
        )
        if authn_statement is not None:
            session_not_on_or_after = authn_statement.get('SessionNotOnOrAfter')
            if session_not_on_or_after:
                return self._parse_datetime(session_not_on_or_after)

        conditions = self.root.find(
            'saml:Assertion/saml:Conditions', NAMESPACES
        )
        if conditions is not None:
            not_on_or_after = conditions.get('NotOnOrAfter')
            if not_on_or_after:
                return self._parse_datetime(not_on_or_after)

